    public var verifyCerts: Bool
    public var useMasque: Bool
    public var masqueHost: String?
    public var masquePort: UInt16?
    public var eventBuffer: UInt64

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(serverHost: String, serverPort: UInt16, 
        /**
         * Device ID (UUID string). Empty on fresh install.
         */myDeviceId: String, 
        /**
         * User ID (hash of identity public key). Empty on fresh install.
         */myUserId: String, 
        /**
         * CFE-encoded private key blob (CfePrivateKeysV1). Empty on fresh install.
         */keysCfeData: Data, 
        /**
         * Auth token from Keychain. None on fresh install.
         */authToken: String?, verifyCerts: Bool, useMasque: Bool, masqueHost: String?, masquePort: UInt16?, eventBuffer: UInt64) {
        self.serverHost = serverHost
        self.serverPort = serverPort
        self.myDeviceId = myDeviceId
        self.myUserId = myUserId
        self.keysCfeData = keysCfeData
        self.authToken = authToken
        self.verifyCerts = verifyCerts
        self.useMasque = useMasque
        self.masqueHost = masqueHost
        self.masquePort = masquePort
        self.eventBuffer = eventBuffer
