public enum EngineError: Swift.Error, Equatable, Hashable, Foundation.LocalizedError {

    
    
    case Transport(message: String
    )
    case Tls(message: String
    )
    case Grpc(code: UInt32, message: String
    )
    case Crypto(message: String
    )
    case Config(message: String
    )
    case AlreadyRunning
    case NotRunning
    case Timeout
    case Unauthenticated(message: String
    )
    case Internal(message: String
    )

    

    
    public var errorDescription: String? {
        String(reflecting: self)
    }
    
}

#if compiler(>=6)
extension EngineError: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeEngineError: FfiConverterRustBuffer {
    typealias SwiftType = EngineError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> EngineError {
        let variant: Int32 = try readInt(&buf)
        switch variant {

        

        
        case 1: return .Transport(
            message: try FfiConverterString.read(from: &buf)
            )
        case 2: return .Tls(
            message: try FfiConverterString.read(from: &buf)
            )
        case 3: return .Grpc(
            code: try FfiConverterUInt32.read(from: &buf), 
            message: try FfiConverterString.read(from: &buf)
            )
        case 4: return .Crypto(
            message: try FfiConverterString.read(from: &buf)
            )
        case 5: return .Config(
            message: try FfiConverterString.read(from: &buf)
            )
        case 6: return .AlreadyRunning
        case 7: return .NotRunning
        case 8: return .Timeout
        case 9: return .Unauthenticated(
            message: try FfiConverterString.read(from: &buf)
            )
        case 10: return .Internal(
            message: try FfiConverterString.read(from: &buf)
            )

         default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: EngineError, into buf: inout [UInt8]) {
        switch value {

        

        
        
        case let .Transport(message):
            writeInt(&buf, Int32(1))
            FfiConverterString.write(message, into: &buf)
            
        
        case let .Tls(message):
            writeInt(&buf, Int32(2))
            FfiConverterString.write(message, into: &buf)
            
        
        case let .Grpc(code,message):
            writeInt(&buf, Int32(3))
            FfiConverterUInt32.write(code, into: &buf)
            FfiConverterString.write(message, into: &buf)
            
        
        case let .Crypto(message):
            writeInt(&buf, Int32(4))
            FfiConverterString.write(message, into: &buf)
            
        
        case let .Config(message):
            writeInt(&buf, Int32(5))
            FfiConverterString.write(message, into: &buf)
            
        
        case .AlreadyRunning:
            writeInt(&buf, Int32(6))
        
        
        case .NotRunning:
            writeInt(&buf, Int32(7))
        
        
        case .Timeout:
            writeInt(&buf, Int32(8))
        
        
        case let .Unauthenticated(message):
            writeInt(&buf, Int32(9))
            FfiConverterString.write(message, into: &buf)
            
        
        case let .Internal(message):
            writeInt(&buf, Int32(10))
            FfiConverterString.write(message, into: &buf)
            
        }
    }
}


