    )
    case deleteKeychain(key: String
    )
    case setAuthToken(userId: String, accessToken: String, refreshToken: String, expiresAt: Int64
    )
    case clearAuth
    case registrationComplete(userId: String, deviceId: String
    )
    case saveMessage(envelopeBytes: Data, senderId: String, conversationId: String, timestamp: Int64
    )
    case updateMessageStatus(localId: String, status: UInt8
    )
    case displayMessage(messageId: String, plaintext: Data, senderId: String, conversationId: String, timestamp: Int64
    )
    case deliveryReceipt(messageId: String, conversationId: String, timestamp: Int64
    )
    case sessionEstablished(contactId: String, sessionId: String
    )
    case sessionError(contactId: String, message: String
    )
